package com.acme.service;

import java.io.IOException;
import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import org.springframework.core.io.InputStreamResource;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;

@Service
public class FileDownloadService {
    private static final Path UPLOAD_ROOT = Paths.get("/opt/app/uploads").toAbsolutePath().normalize();

    /**
     * Safely download a file by name. The file must reside within UPLOAD_ROOT.
     * Path traversal is prevented by resolving and normalizing the full path,
     * then verifying it starts with the expected root directory.
     */
    public ResponseEntity<InputStreamResource> download(String filename) throws IOException {
        // Resolve the requested filename against the upload root
        Path requestedPath = UPLOAD_ROOT.resolve(filename).normalize();

        // Critical security check: ensure resolved path is within allowed directory
        if (!requestedPath.startsWith(UPLOAD_ROOT)) {
            throw new SecurityException("Access denied: path traversal detected");
        }

        // Verify the file exists and is a regular file
        if (!Files.exists(requestedPath) || !Files.isRegularFile(requestedPath)) {
            throw new IOException("File not found: " + filename);
        }

        InputStream inputStream = Files.newInputStream(requestedPath);
        String contentType = Files.probeContentType(requestedPath);
        if (contentType == null) {
            contentType = MediaType.APPLICATION_OCTET_STREAM_VALUE;
        }

        HttpHeaders headers = new HttpHeaders();
        headers.add(HttpHeaders.CONTENT_DISPOSITION,
            "attachment; filename=\"" + requestedPath.getFileName().toString() + "\"");

        return ResponseEntity.ok()
            .headers(headers)
            .contentType(MediaType.parseMediaType(contentType))
            .body(new InputStreamResource(inputStream));
    }
}
